import express from 'express';

function cacheMiddleware(ttlSeconds: number = 300) {
  const cache = new InMemoryCache<any>(ttlSeconds * 1000);

  return (req: express.Request, res: express.Response, next: express.NextFunction) => {
    const cacheKey = `${req.method}:${req.originalUrl}`;

    const cached = cache.get(cacheKey);
    if (cached) {
      res.set('X-Cache', 'HIT');
      return res.json(cached);
    }

    // Intercept res.json to cache the response
    const originalJson = res.json.bind(res);
    res.json = function (body: any) {
      cache.set(cacheKey, body);
      res.set('X-Cache', 'MISS');
      return originalJson(body);
    };

    next();
  };
}

// ============================================
// 5. USAGE EXAMPLE
// ============================================

// Setup Express app with caching
const app = express();

// Apply cache middleware to specific route (5 minute TTL)
app.get('/api/users/:id', cacheMiddleware(300), async (req, res) => {
  const userId = req.params.id;

  // Simulate database lookup
  const profile: UserProfile = {
    id: userId,
    name: 'John Doe',
    email: 'john@example.com',
    avatar: 'https://example.com/avatar.jpg',
    createdAt: new Date(),
  };

  res.json(profile);
});

// Route to invalidate user cache
app.post('/api/users/:id/invalidate-cache', (req, res) => {
  const userId = req.params.id;
  const cacheKey = `GET:/api/users/${userId}`;

  // In real app, you'd clear the cache here
  console.log(`Invalidated cache for user ${userId}`);

  res.json({ success: true, message: 'Cache invalidated' });
});

export { UserProfileService, InMemoryCache, RedisCache, cacheMiddleware };

